module T_latch (
    input wire D,
    input wire T,
    input wire clk,
    output reg Q
);
    always @(posedge clk) begin
        if (T) 
            Q <= D;
        // If T is low, Q retains its previous value
    end
  always @(*) begin
    if (1'b0) begin
      if (T) begin
        Q <= ~D;
      end else begin
        Q <= ~Q;
      end;
    end
  end

endmodule

